using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

// ── Configuration ────────────────────────────────────────────────────────────
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var bingApiKey = Environment.GetEnvironmentVariable("BING_SEARCH_API_KEY");
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

if (string.IsNullOrEmpty(bingApiKey))
{
    Console.WriteLine("⚠  BING_SEARCH_API_KEY not set — web search will return simulated results.");
    Console.WriteLine("   Get a key at https://aka.ms/bingapisignup\n");
}

// ── Dependency Injection ─────────────────────────────────────────────────────
var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddHttpClient();
services.AddSingleton(new OpenAIClient(openAiKey));
services.AddChatClient(builder => builder
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId));

var sp = services.BuildServiceProvider();

// ── Tools ────────────────────────────────────────────────────────────────────
var noteService = new NoteService();
var searchTool = new WebSearchTool(
    sp.GetRequiredService<IHttpClientFactory>().CreateClient("BingSearch"),
    bingApiKey);

AITool[] tools =
[
    AIFunctionFactory.Create(searchTool.SearchAsync),
    AIFunctionFactory.Create(noteService.AddNote),
    AIFunctionFactory.Create(noteService.GetAllNotes),
];

// ── Agent ────────────────────────────────────────────────────────────────────
var agent = new ChatClientAgent(
    sp.GetRequiredService<IChatClient>(),
    new ChatClientAgentOptions
    {
        Id = "research-agent",
        Name = "Research Agent",
        Description = "Researches topics using web search and structured note-taking.",
        Instructions = """
            You are a thorough research agent. When given a topic to research:

            1. Break the topic into 2–3 focused research questions.
            2. For each question, use the SearchAsync tool to find relevant information.
            3. For each meaningful finding, use AddNote to record a note with a short title
               and the key facts plus source URLs.
            4. After investigating all questions, call GetAllNotes to review your collected
               findings, then write a well-organized summary covering:
               • Key findings grouped by theme
               • Important details and data points
               • Source attributions

            Be factual and concise. Always cite your sources.
            """,
        Tools = [.. tools],
    },
    sp.GetRequiredService<ILoggerFactory>(),
    sp);

agent.ChatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
};

// ── Run ──────────────────────────────────────────────────────────────────────
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(5));
var session = await agent.CreateSessionAsync(cts.Token);

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    new AgentRunOptions(),
    cts.Token);

// ── Output ───────────────────────────────────────────────────────────────────
Console.WriteLine("══════════════════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("══════════════════════════════════════════════════════════\n");
Console.WriteLine(response.Text);

var notes = noteService.ListNotes();
if (notes.Count > 0)
{
    Console.WriteLine("\n══════════════════════════════════════════════════════════");
    Console.WriteLine($"  RESEARCH NOTES ({notes.Count} collected)");
    Console.WriteLine("══════════════════════════════════════════════════════════\n");

    foreach (var (title, content) in notes)
    {
        Console.WriteLine($"📌 {title}");
        Console.WriteLine($"   {content}\n");
    }
}

