using System.ComponentModel;
using System.Text;
using System.Text.Json;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability via the Bing Search API.
/// Falls back to a descriptive message when no API key is configured.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;
    private readonly string? _apiKey;

    public WebSearchTool(HttpClient httpClient, string? apiKey)
    {
        _httpClient = httpClient;
        _apiKey = apiKey;

        if (!string.IsNullOrEmpty(apiKey))
        {
            _httpClient.DefaultRequestHeaders.TryAddWithoutValidation(
                "Ocp-Apim-Subscription-Key", apiKey);
        }
    }

    [Description("Search the web for information on a query. Returns titles, URLs, and text snippets from relevant web pages.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up")] string query,
        [Description("Number of results to return, between 1 and 10")] int count = 5)
    {
        count = Math.Clamp(count, 1, 10);

        if (string.IsNullOrEmpty(_apiKey))
        {
            return $"[No BING_SEARCH_API_KEY configured — returning simulated results]\n" +
                   $"Searched for: \"{query}\" — no live results available. " +
                   "Set the BING_SEARCH_API_KEY environment variable to enable real web search.";
        }

        try
        {
            var url = $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count={count}&textFormat=Raw";
            var response = await _httpClient.GetAsync(url);
            response.EnsureSuccessStatusCode();

            using var doc = await JsonDocument.ParseAsync(
                await response.Content.ReadAsStreamAsync());
            var root = doc.RootElement;

            if (!root.TryGetProperty("webPages", out var webPages) ||
                !webPages.TryGetProperty("value", out var results))
            {
                return $"No results found for: \"{query}\"";
            }

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"\n");

            int i = 1;
            foreach (var result in results.EnumerateArray())
            {
                var title = result.GetProperty("name").GetString();
                var resultUrl = result.GetProperty("url").GetString();
                var snippet = result.GetProperty("snippet").GetString();

                sb.AppendLine($"{i}. {title}");
                sb.AppendLine($"   URL: {resultUrl}");
                sb.AppendLine($"   {snippet}");
                sb.AppendLine();
                i++;
            }

            return sb.ToString();
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }
}

